turn1_code:
import re

def count_words(text):
    if not text:
        return 0
    words = re.findall(r'\b\w+\b', text)
    return len(words)

turn2_code:
import re

def count_specific_word(text_input, target_word):
    if not text_input or not target_word:
        return 0
    pattern = r'\b' + re.escape(target_word) + r'\b'
    matches = re.findall(pattern, text_input, re.IGNORECASE)
    return len(matches)

